import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

// This function can be marked `async` if using `await` inside
export function proxy(request: NextRequest) {
  // Check if the user is trying to access protected admin routes
  if (request.nextUrl.pathname.startsWith('/admin') || request.nextUrl.pathname.startsWith('/portal')) {
    
    // Check for the JWT session cookie set by our /api/admin/auth/login route
    const hasSessionCookie = request.cookies.has('auth_session');

    // Also check for Authorization header (Bearer token)
    const hasAuthHeader = request.headers.has('Authorization');

    if (!hasSessionCookie && !hasAuthHeader) {
      // Not authenticated, redirect to a login/unauthorized page
      return NextResponse.redirect(new URL('/?error=unauthorized', request.url));
    }
  }

  // Add basic security headers to all responses
  const response = NextResponse.next();
  
  response.headers.set('X-XSS-Protection', '1; mode=block');
  response.headers.set('X-Frame-Options', 'DENY');
  response.headers.set('X-Content-Type-Options', 'nosniff');
  response.headers.set('Referrer-Policy', 'strict-origin-when-cross-origin');

  return response;
}

// See "Matching Paths" below to learn more
export const config = {
  matcher: [
    /*
     * Match all request paths except for the ones starting with:
     * - api (API routes)
     * - _next/static (static files)
     * - _next/image (image optimization files)
     * - favicon.ico, sitemap.xml, robots.txt (metadata files)
     */
    '/((?!api|_next/static|_next/image|favicon.ico|sitemap.xml|robots.txt).*)',
  ],
};
